using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new PaymentGateway();
    }

    // --- ChargeAsync Tests ---

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    [DataRow("tok_visa_1", 0.50)]
    [DataRow("tok_mastercard", 9999.99)]
    [DataRow("tok_amex", 1.00)]
    public async Task ChargeAsync_VariousValidAmounts_ReturnsSuccess(string token, double amount)
    {
        var result = await _gateway.ChargeAsync(token, (decimal)amount);

        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid", -10m));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync(token!, 25.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_UniqueChargeIdPerTransaction()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa", 10m);
        var result2 = await _gateway.ChargeAsync("tok_visa", 10m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // --- RefundAsync Tests ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 75.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsNotNull(refund.RefundId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_InvalidChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 30.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(secondRefund.Success);
    }

    [TestMethod]
    public async Task RefundAsync_UniqueRefundIdPerRefund()
    {
        var charge1 = await _gateway.ChargeAsync("tok_valid", 10m);
        var charge2 = await _gateway.ChargeAsync("tok_valid", 20m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }
}

